module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
    reg [31:0] yout_r = 0;
    reg [15:0] areg, breg;
    reg [4:0] i = 0;
    reg done_r = 0;

    assign yout = yout_r;
    assign done = done_r;

    always @(posedge clk, negedge rst_n) begin
        if (!rst_n)
            i <= 0;
        else if (start && i < 17)
            i <= i + 1;
        else if (!start)
            i <= 0;
    end

    always @(posedge clk, negedge rst_n) begin
        if (!rst_n)
            done_r <= 0;
        else if (i == 16)
            done_r <= 1;
        else if (i == 17)
            done_r <= 0;
    end

    always @(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end else if (start) begin
            if (i == 0) begin
                areg <= ain;
                breg <= bin;
            end else if (i < 17) begin
                if (areg[i-1])
                    yout_r <= yout_r + (breg << (i-1));
            end
        end
    end
endmodule
